def find_smallest_missing_positive(nums):
    n = len(nums)
    i = 0
    while i < n:
        val = nums[i]
        # Place positive numbers within the range [1, n] at their correct index.
        # E.g., number 3 should be at index 2 (nums[2] = 3).
        # We also check if nums[val - 1] is already val to avoid infinite loops with duplicates.
        if 1 <= val <= n and nums[val - 1] != val:
            nums[i], nums[val - 1] = nums[val - 1], nums[i]
        else:
            i += 1

    # After rearrangement, iterate through the array.
    # The first index 'i' where nums[i] is not 'i + 1' indicates that 'i + 1' is missing.
    for i in range(n):
        if nums[i] != i + 1:
            return i + 1

    # If all numbers from 1 to n are present, then the smallest missing positive is n + 1.
    return n + 1
